parameters.jsCode:
const items = $input.all();
const raw = items[0].json.text || items[0].json.output || '';

const cleaned = raw.replace(/```json|```/g, '').trim();
const match = cleaned.match(/\[[\s\S]*\]/);
if (!match) {
  return [{ json: { error: 'No JSON array in response', raw } }];
}

try {
  const leads = JSON.parse(match[0]);
  return leads.map(lead => ({ json: lead }));
} catch(e) {
  return [{ json: { error: 'JSON parse failed', raw, message: e.message } }];
}

